# Plus One — O(n) time, O(1) space
# KEY INSIGHT: propagate carry right to left; all-9s needs new leading digit

def plusOne(digits):
    for i in range(len(digits) - 1, -1, -1):
        if digits[i] < 9:
            digits[i] += 1
            return digits
        digits[i] = 0  # digit was 9, set to 0 and carry

    # All digits were 9 (e.g., [9,9,9] → [1,0,0,0])
    return [1] + digits
